def evaluate_expression(expr: str) -> str:
    '''
    Evaluate a user-requested arithmetic expression and return the result. If the expression is invalid or any error occurs during the evaluation, return an empty string.

    Args:
        expr (str): The user-requested arithmetic expression to evaluate.

    Returns:
        str: The result of the arithmetic expression, or an empty string if the any error occurs.
    '''
    if not isinstance(expr, str):
        return ""

    expr = expr.strip()

    if not expr:
        return ""

    # Whitelist allowed characters: digits, operators, parentheses, decimal point, and whitespace
    allowed_chars = set("0123456789+-*/.() \t")
    if not all(c in allowed_chars for c in expr):
        return ""

    # Prevent multiple operators in a row or invalid patterns
    import re

    # Check for invalid patterns like consecutive operators (except for unary minus/plus)
    if re.search(r'[+\-*/]\s*[+\-*/]', expr):
        # Allow unary operators at the start or after opening parenthesis
        if not re.match(r'^[+\-]', expr) and not re.search(r'\([+\-]', expr):
            return ""

    try:
        # Use ast.literal_eval with a restricted namespace for safety
        import ast

        # Parse the expression as an AST to validate it
        tree = ast.parse(expr, mode='eval')

        # Validate that the AST only contains allowed node types
        allowed_node_types = (
            ast.Expression,
            ast.BinOp,
            ast.UnaryOp,
            ast.Num,
            ast.Constant,
            ast.Add,
            ast.Sub,
            ast.Mult,
            ast.Div,
            ast.UAdd,
            ast.USub,
        )

        def validate_node(node):
            if not isinstance(node, allowed_node_types):
                return False
            for child in ast.iter_child_nodes(node):
                if not validate_node(child):
                    return False
            return True

        if not validate_node(tree):
            return ""

        # Evaluate the expression
        result = eval(compile(tree, '<string>', 'eval'))

        # Ensure result is a number
        if not isinstance(result, (int, float)):
            return ""

        # Handle infinity and NaN
        if isinstance(result, float):
            if result != result or result == float('inf') or result == float('-inf'):
                return ""

        # Return the result as a string
        if isinstance(result, float) and result.is_integer():
            return str(int(result))
        else:
            return str(result)

    except (SyntaxError, ValueError, TypeError, ZeroDivisionError, NameError, AttributeError):
        return ""
    except Exception:
        return ""

