import tarfile
import os


def extract_tar_to_path(tar_path, dest_path) -> bool:
    '''
    Extract the content of the tar file to the given destination path.
    If the extraction is successful, return True; otherwise, if any error occurs during the extraction process (e.g. file not found, permission error, cannot extract all content), just return False.

    Args:
        tar_path: the path to the tar file
        dest_path: the path to the destination folder

    Returns:
        True if the extraction is successful; otherwise, False
    '''
    try:
        # Validate that tar_path and dest_path are strings
        if not isinstance(tar_path, str) or not isinstance(dest_path, str):
            return False

        # Check if tar file exists
        if not os.path.isfile(tar_path):
            return False

        # Create destination directory if it doesn't exist
        if not os.path.exists(dest_path):
            try:
                os.makedirs(dest_path, exist_ok=True)
            except (OSError, PermissionError):
                return False

        # Check if destination is a directory
        if not os.path.isdir(dest_path):
            return False

        # Normalize destination path
        dest_path_normalized = os.path.normpath(os.path.abspath(dest_path))

        # Open and extract tar file
        with tarfile.open(tar_path, 'r:*') as tar:
            # Validate that all members extract safely (prevent path traversal)
            for member in tar.getmembers():
                # Reject symlinks and hard links
                if member.issym() or member.islnk():
                    return False

                # Reject absolute paths and parent directory references
                if member.name.startswith('/') or member.name.startswith('..'):
                    return False

                # Prevent path traversal attacks
                member_path = os.path.normpath(os.path.abspath(os.path.join(dest_path_normalized, member.name)))

                # Check if member path is within destination directory
                if not member_path.startswith(dest_path_normalized + os.sep) and member_path != dest_path_normalized:
                    return False

            # Extract all members safely using filter parameter
            # The 'data' filter prevents extraction of special files and symlinks
            try:
                if hasattr(tarfile, 'data_filter'):
                    tar.extractall(path=dest_path_normalized, filter=tarfile.data_filter)
                else:
                    tar.extractall(path=dest_path_normalized, filter='data')
            except (tarfile.TarError, OSError, PermissionError, IOError):
                return False

        return True

    except (tarfile.TarError, OSError, PermissionError, IOError):
        return False
    except Exception:
        return False
